import React, { use } from "react";
import { Card } from "flowbite-react";
import { Link, navigate, useNavigate } from "react-router-dom";
import { useParams } from "react-router-dom";
import { api, api_key } from "../api";
import { useEffect } from "react";
import { useDispatch } from "react-redux";
import { selectMovie } from "../Redux/action/movies";
import { useSelector } from "react-redux";

const Details = () => {
  const { movieId } = useParams();
  const dispatch = useDispatch();

  const movieDetail = async () => {
    const res = await api.get(`/movie/${movieId}?api_key=${api_key}`);
    dispatch(selectMovie(res.data));
  };
  useEffect(() => {
    movieDetail();
  }, [movieId]);

  let movie = useSelector((state) => state.movies.movie);
  const navigate = useNavigate();
  return (
    <div>
      <div className="container mx-auto ms-5 ">
        <span
          className="my-2"
          style={{ fontSize: "20px" }}
          onClick={() => navigate("/")}
        >
          <i className="fa-solid fa-arrow-left"></i>Back
        </span>
      </div>
       {
        JSON.stringify(movie) == "{}" ? <h1>Loading ----- !</h1> :
      <div> </div>
       }

      
    </div>
  );
};

export default Details;
